@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;
    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/UserActivityTracker.razor.js");

        await _module.InvokeVoidAsync("init", _element, _dotNetRef, TimeoutSeconds * 1000);
    }

    [JSInvokable]
    public async Task OnIdleTriggered()
    {
        if (_isIdle) return;
        _isIdle = true;
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveTriggered()
    {
        if (!_isIdle) return;
        _isIdle = false;
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }

        _dotNetRef?.Dispose();
    }
}

let timer = null;
let handler = null;
let dotNetRef = null;
let element = null;

const events = ["mousemove", "keydown", "click", "scroll"];

function resetTimer(timeoutMs) {
    clearTimeout(timer);
    timer = setTimeout(async () => {
        await dotNetRef.invokeMethodAsync("OnIdleTriggered");
    }, timeoutMs);
}

export function init(el, ref, timeoutMs) {
    element = el;
    dotNetRef = ref;

    handler = async () => {
        await dotNetRef.invokeMethodAsync("OnActiveTriggered");
        resetTimer(timeoutMs);
    };

    for (const evt of events) {
        element.addEventListener(evt, handler, { passive: true });
    }

    resetTimer(timeoutMs);
}

export function dispose() {
    clearTimeout(timer);
    if (element && handler) {
        for (const evt of events) {
            element.removeEventListener(evt, handler);
        }
    }
    timer = null;
    handler = null;
    dotNetRef = null;
    element = null;
}

